import React from "react";
import "../styles/landing.css";
import hero from "../assets/lostfound.svg";

export default function Hero() {
  return (
    <section className="hero">

      <h1>
        Lost something on campus?
        <br />
        <span>Find it again.</span>
      </h1>

      <p>
        A simple platform where students report lost items
        and help return them to their owners.
      </p>

      <div className="hero-buttons">
        <button className="primary">Report Lost Item</button>
        <button className="secondary">View Found Items</button>
      </div>

      <img src={hero} alt="lost and found illustration" className="hero-img"/>

    </section>
  );
}
